import { useState, useEffect } from 'react';
import { auth, db } from '../services/firebaseConfig';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { doc, getDoc, setDoc, deleteDoc, query, collection, where, getDocs, updateDoc } from 'firebase/firestore';
import { User, UserRole } from '../types';
import { UserService } from '../services/firebaseBackend';

export const useAuthStatus = () => {
    const [user, setUser] = useState<User | null>(null);
    const [cargando, setCargando] = useState(true);

    useEffect(() => {
        const cachedInit = localStorage.getItem('sgd_user_cache');
        if (cachedInit) {
            setUser(JSON.parse(cachedInit));
        }

        const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
            if (firebaseUser) {
                try {
                    const userRef = doc(db, "users", firebaseUser.uid);
                    const userSnap = await getDoc(userRef);
                    const email = firebaseUser.email || '';

                    // Definición de dominio institucional
                    const INSTITUTIONAL_DOMAIN = '@ugp-ssmso.cl';
                    const isInstitutional = email.toLowerCase().endsWith(INSTITUTIONAL_DOMAIN);

                    const adminEmails = ['admin@empresa.com'];
                    // Solo cuentas institucionales pueden ser administradores por prefijo o lista blanca
                    const shouldBeAdmin = isInstitutional && (adminEmails.includes(email) || email.toLowerCase().startsWith('admin'));

                    if (userSnap.exists()) {
                        const userData = userSnap.data() as User;

                        if (userData.active === false) {
                            await signOut(auth);
                            localStorage.removeItem('sgd_user_cache');
                            setUser(null);
                            alert("Su cuenta ha sido desactivada.");
                            return;
                        }

                        // Si es una cuenta externa pero por alguna razón tiene rol de Analista, 
                        // el administrador deberá haberlo asignado manualmente en el panel de usuarios.
                        // Aquí solo actualizamos el estado del admin institucional.
                        if (shouldBeAdmin && userData.role !== UserRole.ADMIN) {
                            const updatedUser = { ...userData, role: UserRole.ADMIN, organization: 'Administración Sistema' };
                            await updateDoc(userRef, { role: UserRole.ADMIN, organization: 'Administración Sistema' });
                            setUser(updatedUser);
                        } else {
                            setUser(userData);
                        }
                    } else {
                        // Búsqueda de perfil legacy por email
                        let existingProfile: User | null = null;
                        let oldDocRef = null;

                        if (email) {
                            const q = query(collection(db, "users"), where("email", "==", email));
                            const querySnapshot = await getDocs(q);
                            if (!querySnapshot.empty) {
                                const docFound = querySnapshot.docs[0];
                                existingProfile = docFound.data() as User;
                                oldDocRef = docFound.ref;
                            }
                        }

                        if (existingProfile && oldDocRef) {
                            // Si el perfil existía (ej: cargado por excel)
                            // Pero es una cuenta externa (Gmail), forzamos GUEST a menos que el administrador 
                            // haya indicado explícitamente otro rol en la carga previa.
                            const migratedUser: User = {
                                ...existingProfile,
                                id: firebaseUser.uid, 
                                avatar: firebaseUser.photoURL || existingProfile.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(existingProfile.name || 'User')}`, 
                                // Forzar GUEST si es externo, a menos que ya tuviera un rol definido manualmente en base de datos
                                role: isInstitutional ? (shouldBeAdmin ? UserRole.ADMIN : existingProfile.role) : UserRole.GUEST,
                                active: true,
                                organization: isInstitutional ? existingProfile.organization : 'Acceso Externo (Visitante)'
                            };

                            const safeUser = JSON.parse(JSON.stringify(migratedUser));
                            await setDoc(userRef, safeUser);
                            await UserService.migrateLegacyReferences(existingProfile.id, firebaseUser.uid);
                            await deleteDoc(oldDocRef);
                            setUser(migratedUser);
                        } else {
                            // NUEVO USUARIO (Autoregistro o primer login Google)
                            // REGLA DE ORO: Si no es institucional, SIEMPRE es GUEST.
                            const newUser: User = {
                                id: firebaseUser.uid,
                                email: email,
                                name: firebaseUser.displayName || email.split('@')[0],
                                nickname: email.split('@')[0],
                                role: (shouldBeAdmin && isInstitutional) ? UserRole.ADMIN : UserRole.GUEST,
                                avatar: firebaseUser.photoURL || `https://ui-avatars.com/api/?name=${firebaseUser.displayName || email}`,
                                organization: isInstitutional ? 'Servicio de Salud Metropolitano Sur Oriente' : 'Acceso Externo (Visitante)',
                                active: true 
                            };

                            const safeNewUser = JSON.parse(JSON.stringify(newUser));
                            await setDoc(userRef, safeNewUser);
                            setUser(newUser);
                        }
                    }
                } catch (error) {
                    console.error("Error fetching/creating user profile:", error);
                    setUser(null);
                }
            } else {
                const cached = localStorage.getItem('sgd_user_cache');
                if (cached) {
                    try {
                        const parsedUser = JSON.parse(cached);
                        if (parsedUser && parsedUser.id && parsedUser.active !== false) {
                            setUser(parsedUser);
                        } else {
                            setUser(null);
                        }
                    } catch (e) {
                        setUser(null);
                    }
                } else {
                    setUser(null);
                }
            }
            setCargando(false);
        });

        return () => unsubscribe(); 
    }, []);

    return { user, cargando };
};

