import React, { useState, useEffect } from 'react';
import { UserService } from '../services/firebaseBackend';
import { User, UserRole } from '../types';
import { UserCog, Save, Lock, Mail, Shield, Building, Globe, ShieldAlert } from 'lucide-react';

interface Props {
  user: User;
  onUpdate: () => void;
}

const Profile: React.FC<Props> = ({ user, onUpdate }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const isExternal = !user.email.toLowerCase().endsWith('@ugp-ssmso.cl');

  useEffect(() => {
    setEmail(user.email);
    setPassword(user.password || '');
    setConfirmPassword(user.password || '');
  }, [user]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setMessage(null);

    if (password !== confirmPassword) {
        setMessage({ type: 'error', text: 'Las contraseñas no coinciden.' });
        return;
    }

    if (!email.includes('@')) {
        setMessage({ type: 'error', text: 'Ingrese un correo electrónico válido.' });
        return;
    }

    setLoading(true);
    try {
        await UserService.update(user.id, {
            email,
            password: password || undefined 
        });

        onUpdate();
        setMessage({ type: 'success', text: 'Perfil actualizado correctamente.' });
    } catch (err: any) {
        setMessage({ type: 'error', text: err.message });
    } finally {
        setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto py-6 animate-fadeIn">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
            <div>
                <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                    <UserCog className="text-indigo-600" />
                    Mi Perfil
                </h1>
                <p className="text-slate-500">Gestione la información de acceso a su cuenta.</p>
            </div>
        </div>

        {isExternal && (
            <div className="bg-indigo-600 text-white p-4 rounded-xl mb-6 shadow-md border border-indigo-500 flex items-center gap-4 animate-fadeIn">
                <div className="bg-white/20 p-2 rounded-lg">
                    <ShieldAlert size={20} />
                </div>
                <div className="text-sm">
                    <p className="font-bold uppercase tracking-tight">Acceso de Invitado Detectado</p>
                    <p className="opacity-90">Su cuenta es externa al dominio institucional. Tiene permisos de **Solo Lectura**.</p>
                </div>
            </div>
        )}

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-6 bg-slate-50/50 border-b border-slate-100 flex items-center gap-4">
                <div className="w-16 h-16 rounded-full bg-indigo-100 flex items-center justify-center text-2xl font-bold text-indigo-600 border-2 border-white shadow-sm overflow-hidden">
                    {user.avatar ? <img src={user.avatar} className="w-full h-full object-cover" /> : user.name.charAt(0)}
                </div>
                <div>
                    <div className="flex items-center gap-2">
                        <h2 className="text-lg font-bold text-slate-800">{user.name}</h2>
                        {isExternal && (
                            <span className="bg-white text-indigo-600 border border-indigo-200 text-[10px] font-black px-2 py-0.5 rounded uppercase tracking-tighter shadow-sm">Externo</span>
                        )}
                    </div>
                    <p className="text-sm text-slate-500 font-mono">@{user.nickname || 'usuario'}</p>
                </div>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                     <div>
                        <label className="block text-xs font-bold text-slate-400 uppercase mb-1 flex items-center gap-1">
                            <Building size={12} /> Organización
                        </label>
                        <input 
                            type="text" 
                            value={user.organization} 
                            disabled 
                            className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-slate-500 cursor-not-allowed font-medium"
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-400 uppercase mb-1 flex items-center gap-1">
                            <Shield size={12} /> Rol de Usuario
                        </label>
                         <input 
                            type="text" 
                            value={user.role} 
                            disabled 
                            className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-slate-500 cursor-not-allowed font-bold"
                        />
                    </div>
                </div>

                <hr className="border-slate-100" />

                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                            <Mail size={16} className="text-indigo-500" />
                            Correo Electrónico
                        </label>
                        <input 
                            type="email" 
                            value={email} 
                            onChange={(e) => setEmail(e.target.value)}
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 bg-white" 
                            required
                        />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                                <Lock size={16} className="text-indigo-500" />
                                Contraseña
                            </label>
                            <input 
                                type="password" 
                                value={password} 
                                onChange={(e) => setPassword(e.target.value)}
                                className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 bg-white" 
                                placeholder="Nueva contraseña..."
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                                <Lock size={16} className="text-indigo-500" />
