                                </label>
                                {role === UserRole.ANALYST && (
                                    <label className="flex items-center gap-3 p-2 bg-white rounded border border-indigo-200 cursor-pointer hover:bg-indigo-100/50 transition-colors">
                                        <input 
                                            type="checkbox" 
                                            checked={canAccessReferents}
                                            onChange={(e) => setCanAccessReferents(e.target.checked)}
                                            className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500"
                                        />
                                        <div className="flex items-center gap-2">
                                            <UserCheck size={16} className="text-indigo-500" />
                                            <span className="text-sm font-medium text-slate-700">Habilitar Vista de Referentes</span>
                                        </div>
                                    </label>
                                )}
                            </div>
                        </div>
                    )}

                    <div className="md:col-span-2 flex justify-end mt-2">
                        <button type="submit" className="bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition-colors">
                            {editingUserId ? 'Guardar Cambios' : 'Crear Usuario'}
                        </button>
                    </div>
                </form>
            </div>
        )}

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                        <tr>
                            <th className="px-6 py-3">Usuario</th>
                            <th className="px-6 py-3">Permisos</th>
                            <th className="px-6 py-3 text-center">Estado</th>
                            <th className="px-6 py-3">Rol</th>
                            <th className="px-6 py-3">Organización</th>
                            <th className="px-6 py-3 text-right">Acciones</th>
                        </tr>
                    </thead>
                    <tbody>
                        {users.map(u => (
                            <tr key={u.id} className={`border-b border-slate-50 hover:bg-slate-50 transition-colors ${u.active === false ? 'opacity-60 bg-slate-50/50' : ''}`}>
                                <td className="px-6 py-4 flex items-center gap-3">
                                    <img src={u.avatar} alt={u.name} className="w-8 h-8 rounded-full bg-slate-200" />
                                    <div>
                                        <p className="font-medium text-slate-900">{u.name}</p>
                                        <p className="text-xs text-slate-500">{u.email}</p>
                                    </div>
                                </td>
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-3">
                                        <button 
                                            onClick={() => handleTogglePermission(u, 'canAccessReports')}
                                            disabled={updatingId === `${u.id}-canAccessReports`}
                                            className={`p-1.5 rounded-lg transition-all flex items-center justify-center
                                                ${u.canAccessReports !== false 
                                                    ? 'bg-green-50 text-green-600 hover:bg-green-100' 
                                                    : 'bg-slate-50 text-slate-300 hover:bg-slate-100 hover:text-slate-400'}`}
                                            title={u.canAccessReports !== false ? "Deshabilitar Reportes" : "Habilitar Reportes"}
                                        >
                                            {updatingId === `${u.id}-canAccessReports` ? <Loader2 size={16} className="animate-spin" /> : <PieChart size={16} />}
                                        </button>

                                        {u.role === UserRole.ANALYST && (
                                            <button 
                                                onClick={() => handleTogglePermission(u, 'canAccessReferents')}
                                                disabled={updatingId === `${u.id}-canAccessReferents`}
                                                className={`p-1.5 rounded-lg transition-all flex items-center justify-center
                                                    ${u.canAccessReferents !== false 
                                                        ? 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100' 
                                                        : 'bg-slate-50 text-slate-300 hover:bg-slate-100 hover:text-slate-400'}`}
                                                title={u.canAccessReferents !== false ? "Deshabilitar Referentes" : "Habilitar Referentes"}
                                            >
                                                {updatingId === `${u.id}-canAccessReferents` ? <Loader2 size={16} className="animate-spin" /> : <UserCheck size={16} />}
                                            </button>
                                        )}
                                    </div>
                                </td>
                                <td className="px-6 py-4 text-center">
                                    <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${u.active !== false ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-slate-200 text-slate-500 border border-slate-300'}`}>
                                        {u.active !== false ? 'Activo' : 'Inactivo'}
                                    </span>
                                </td>
                                <td className="px-6 py-4">
                                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium 
                                        ${u.role === UserRole.ADMIN ? 'bg-purple-100 text-purple-800' : 
                                          u.role === UserRole.COORDINATOR ? 'bg-blue-100 text-blue-800' : 
                                          u.role === UserRole.GUEST ? 'bg-slate-100 text-slate-600 border border-slate-200' :
                                          'bg-green-100 text-green-800'}`}>
                                        {u.role === UserRole.GUEST ? 'Visitante' : u.role}
                                    </span>
                                </td>
                                <td className="px-6 py-4 text-slate-600">{u.organization}</td>
                                <td className="px-6 py-4 text-right">
                                    <div className="flex justify-end gap-1">
                                        <button 
                                            onClick={() => handleToggleStatus(u)}
                                            className={`p-1.5 rounded transition-colors ${u.active !== false ? 'text-slate-400 hover:text-red-600 hover:bg-red-50' : 'text-slate-400 hover:text-green-600 hover:bg-green-50'}`}
                                            title={u.active !== false ? "Inactivar usuario" : "Activar usuario"}
                                        >
                                            <Power size={18} />
                                        </button>
                                        <button 
                                            onClick={() => handleEdit(u)}
                                            className="text-slate-400 hover:text-indigo-600 p-1.5 hover:bg-indigo-50 rounded transition-colors"
                                            title="Editar usuario"
                                        >
                                            <Pencil size={18} />
                                        </button>
                                        <button 
                                            onClick={() => handleDelete(u.id)}
                                            className="text-slate-400 hover:text-red-600 p-1.5 hover:bg-red-50 rounded transition-colors"
                                            title="Eliminar permanentemente"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        {users.length === 0 && !loading && (
                            <tr><td colSpan={6} className="px-6 py-8 text-center text-slate-400">No hay usuarios registrados.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );
};

export default AdminUsers;

import React, { useState, useEffect } from 'react';
import { useLocation, Link, useNavigate } from 'react-router-dom';
import { Menu, X, FileText, BarChart2, PlusCircle, LogOut, User as UserIcon, Users, ClipboardList, Inbox, Database, Settings, ListTodo, Network, PieChart, UserCheck, BookOpen, Shield } from 'lucide-react';
import { User, UserRole, DocState, Document } from '../types';
import { NotificationService } from '../services/firebaseBackend';

interface LayoutProps {
  children: React.ReactNode;
  user: User;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, user, onLogout }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [inboxCount, setInboxCount] = useState(0);
  const location = useLocation();

  const isActive = (path: string) => location.pathname === path ? 'bg-slate-800 text-white shadow-inner' : 'text-slate-300 hover:bg-slate-800 hover:text-white';

  useEffect(() => {
    if (!user?.id) return;

    const unsubscribeInbox = NotificationService.subscribeToUnreadCount(user.id, (count) => {
        setInboxCount(count);
    });

    return () => {
        if (unsubscribeInbox) unsubscribeInbox();
    };
  }, [user.id]); 

  const NavItem = ({ to, icon: Icon, label, badge }: { to: string, icon: any, label: string, badge?: number }) => (
    <Link
      to={to}
      onClick={() => setIsSidebarOpen(false)}
      className={`flex items-center space-x-3 px-4 py-3 rounded-lg transition-all duration-200 group ${isActive(to)}`}
    >
      <div className="relative">
        <Icon 
            size={20} 
            className={isActive(to).includes('bg-slate-800') ? 'text-indigo-400' : 'text-slate-400 group-hover:text-white'} 
        />
        {badge !== undefined && badge > 0 && (
            <span className="absolute -top-2.5 -right-2.5 flex h-5 w-5 items-center justify-center rounded-full bg-red-600 text-[10px] font-black text-white shadow-md ring-2 ring-slate-900 animate-pulse px-1">
                {badge > 99 ? '99+' : badge}
            </span>
        )}
      </div>
      <span className="font-medium flex-1">{label}</span>
    </Link>
  );

  const isAdminOrCoord = user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR;
  const isGuest = user.role === UserRole.GUEST;
  const canAccessReports = isAdminOrCoord || isGuest || (user.role === UserRole.ANALYST && user.canAccessReports);
  const canAccessReferents = isAdminOrCoord || (user.role === UserRole.ANALYST && user.canAccessReferents);

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/60 z-20 md:hidden backdrop-blur-sm transition-opacity" onClick={() => setIsSidebarOpen(false)} />
      )}
      <aside className={`fixed inset-y-0 left-0 z-30 w-64 bg-slate-900 text-white transform transition-transform duration-300 ease-in-out md:translate-x-0 md:static md:flex-shrink-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-full flex flex-col">
          <div className="p-6 border-b border-slate-800 flex justify-between items-center flex-shrink-0 bg-slate-950/30">
            <div>
                <h1 className="text-xl font-bold tracking-tight text-white">SGD</h1>
                <p className="text-[10px] text-indigo-400 font-bold uppercase tracking-widest">Gestión Documental</p>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden text-slate-400 hover:text-white">
                <X size={24} />
            </button>
          </div>
          <nav className="flex-1 px-4 py-6 space-y-1.5 overflow-y-auto">
            <div className="pb-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest px-4">Gestión Principal</div>
            <NavItem to="/" icon={BarChart2} label="Dashboard" />

            {!isGuest && (
              <>
                <NavItem to="/inbox" icon={Inbox} label="Bandeja de Entrada" badge={inboxCount} />
                <NavItem to="/worklist" icon={ListTodo} label="Lista de Trabajo" />
                <NavItem to="/new" icon={PlusCircle} label="Nueva Solicitud" />
              </>
            )}

            {(canAccessReports || canAccessReferents || isAdminOrCoord) && (
              <>
                <div className="pt-6 pb-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest px-4">Administración</div>
                {canAccessReports && <NavItem to="/admin/reports" icon={PieChart} label="Reportes" />}
                {isAdminOrCoord && (
                    <>
                        <NavItem to="/admin/structure" icon={Network} label="Estructura" />
                        <NavItem to="/admin/assignments" icon={ClipboardList} label="Asignaciones" />
                    </>
                )}
                {canAccessReferents && <NavItem to="/admin/referents" icon={UserCheck} label="Referentes" />}
                {user.role === UserRole.ADMIN && (
                    <>
                        <NavItem to="/admin/database" icon={Database} label="Base de Datos" />
                        <NavItem to="/admin/users" icon={Users} label="Usuarios" />
                    </>
                )}
              </>
            )}
            <div className="pt-6 pb-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest px-4">Ayuda y Soporte</div>
            <NavItem to="/manual" icon={BookOpen} label="Manual de Usuario" />
            <NavItem to="/profile" icon={Settings} label="Mi Perfil" />
          </nav>

          {isGuest && (
            <div className="px-4 py-3 mx-4 mb-4 bg-indigo-500/10 border border-indigo-500/20 rounded-xl">
               <div className="flex items-center gap-2 text-indigo-400 mb-1">
                  <Shield size={14} />
                  <span className="text-[10px] font-black uppercase tracking-widest">Rol Visitante</span>
               </div>
               <p className="text-[10px] text-slate-400 leading-tight">Acceso restringido a solo lectura institucional.</p>
            </div>
          )}

          <div className="p-4 border-t border-slate-800 flex-shrink-0 bg-slate-950/20">
            <button onClick={onLogout} className="w-full flex items-center justify-center space-x-2 bg-slate-800 hover:bg-red-900/40 hover:text-red-200 p-2.5 rounded-lg transition-all text-sm font-semibold border border-transparent hover:border-red-800/50">
                <LogOut size={16} />
                <span>Cerrar Sesión</span>
            </button>
          </div>
        </div>
      </aside>
      <div className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="bg-white border-b border-gray-200 p-4 flex items-center justify-between md:hidden flex-shrink-0 shadow-sm">
            <button onClick={() => setIsSidebarOpen(true)} className="text-slate-600 hover:bg-slate-50 p-1 rounded-md"><Menu size={24} /></button>
            <div className="flex flex-col items-center">
              <span className="font-bold text-slate-900 text-sm">SGD Mobile</span>
              {!isGuest && <span className="text-[10px] text-indigo-600 font-bold uppercase tracking-tight">Bandeja {inboxCount > 0 ? `(${inboxCount})` : ''}</span>}
            </div>
            <div className="w-6" />
        </header>
        <main className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-50/50">{children}</main>
      </div>
    </div>
  );
};

export default Layout;
